var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"옛날 옛날에 운명을 볼 줄 아는 여인이 있었다네.","JPN":"むかしむかし、運命を見ることのできる女がいた。","ENG":"Long long ago, there once lived a maiden whose gift was to foresee what lay ahead.","TWN":"很久很久以前，有個懂得算命的女人。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"그 여인은 자신이 가장 사랑하는 가족의 죽음을 막기 위해 목숨을 대신 바쳤지.","JPN":"その女はもっとも愛する家族を死から遠ざける代償として自らの命を捧げた。","ENG":"The maiden offered up her own life as sacrifice, to save her most beloved family member.","TWN":"她因為要拯救心愛的家族免於一死，而獻出自己的性命。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 여인의 희생을 원통하게 여긴 가족은 모든 인간을 증오하며 눈 먼 복수를 하게 됐어.","JPN":"しかし、女の犠牲を無念に思った家族は人間すべてを憎み、復讐の鬼と化して復讐をするようになった。","ENG":"Alas, fortune took an unexpected turn. Her family became enraged at her death, taking vengeance on all of mankind.","TWN":"然而家族對於女人的犧牲感到憤恨不平，因此憎恨人類，於是展開盲目的報復。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"여인의 희생이 무색하게도, 그녀의 가족은 죽음보다 더한 복수의 굴레에 갇히고 말았다네.","JPN":"女の犠牲も無駄となるくらい、彼女の家族は死よりもひどい復讐という檻に囚われてしまったとさ。","ENG":"The maiden’s sacrifice went to vain, and her family lives on, bound by the curse of vengeance... a curse far more daunting than death itself.","TWN":"結果女人的犧牲完全是白費力氣，她的家族則是困在比死亡更痛苦的復仇牢籠裡。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"어때? 운명이라는 건 참 얄궂지 않나?","JPN":"どうだい？　運命とは実に皮肉じゃのう。","ENG":"What do you say? Fate can be ever so deceitful, no?","TWN":"怎麼樣？命運這回事很折騰人吧？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GUEST_VOICE_NULL_NULL","text":{"KOREA":"하하…… 네에……","JPN":"はは……そうですねえ……","ENG":"Ha ha... I see...","TWN":"哈哈……是啊……"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"주인장~ 한 그릇 더~","JPN":"ご主人～おかわりじゃ～","ENG":"Hey! Another bowl!","TWN":"老闆～再來一碗～"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GUEST_VOICE_NULL_A","text":{"KOREA":"저 애 벌써 우동만 다섯 그릇째야. 저러고도 괜찮은 건가?","JPN":"あの子、もううどん五杯目だよ。大丈夫なのかな？","ENG":"That girl’s on her fifth bowl of noodles. Is she all right?","TWN":"那女生已經吃第五碗烏龍麵咧？她沒問題吧？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"아니, 난 그것보다 머리에 달려 있는 게 신경 쓰이는데.","JPN":"私はそれより頭についているものの方が気になるんだけど。","ENG":"I’m more puzzled about that thing on her head.","TWN":"比起烏龍麵，她頭上的東西更令人在意吧？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GUEST_VOICE_NULL_A","text":{"KOREA":"어디서 코스프레 행사라도 있었나 보지.","JPN":"どこかでコスプレのイベントでもあったんでしょ。","ENG":"Maybe she was at some sort of cosplay convention.","TWN":"可能是剛參加完Cosplay活動吧？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"코스프레 치고는 꼬리가 움직이고 있지 않아?","JPN":"コスプレにしちゃあ尻尾が動いてない？","ENG":"You do realize her tail is moving, as if it’s alive... right?","TWN":"Cosplay有這麼厲害？尾巴還會動？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"푸하- 역시 속세의 요리는 세월이 흘러도 변함 없이 맛있구나.","JPN":"ぷっはー、やはり浮世の料理は月日がたっても相変わらず美味いものじゃのう。","ENG":"Gah! Food in the modern world is still delicious as always.","TWN":"噗哈- 俗世的料理果然不管過多久都一樣好吃！"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"오? 거기 빤히 쳐다보는 녀석. 나한테 할말이라도 있냐?","JPN":"お？　こちらをまじまじと見ているそこの者。何か言いたいことでもあるのか？","ENG":"Oh? You there, the fellow staring at me. You have something to say?","TWN":"嗯？那邊那個一直盯著我瞧的小夥子，你有話要跟我說嗎？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"아…… 아뇨, 시비 걸겠다는 건 아니고…… 조금 신기해보여서요.","JPN":"あ……いえ、ケンカを売るつもりは全然ないんですが……ちょっと不思議で。","ENG":"N-no, I don’t mean any harm... I just thought you looked rather interesting.","TWN":"沒……沒有，我沒有要挑釁的意思……我只是覺得很新奇。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"오! 내 장비에 관심이 있는 게로구나?","JPN":"おお！　わしの装備に興味があるのだな？","ENG":"Aha! You’re amazed by my gears, are you not?","TWN":"喔！你對我的裝備有興趣是嗎？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"좋다! 그 안목을 높이 사서 특별히 내 제자로 받아 주마!","JPN":"よかろう！　その目を高く評価して、特別にわしの弟子にしてやろうではないか！","ENG":"Fate has smiled upon you, young one! I shall accept you as my pupil, just this once!","TWN":"好！看在你這麼有眼光的份上，我就破例收你當徒弟吧！"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"너, 용광로 다루는 법 정도는 알고 있겠지?","JPN":"お主、溶鉱炉を扱う方法くらいは知っておるだろうな？","ENG":"I assume you know your way with blast furnaces, hmm?","TWN":"喂，你知道怎麼使用熔爐吧？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};